#include <iostream>
#include <string>

class Point {
public:
    int x, y;

    Point(int x_coord = 0, int y_coord = 0) : x(x_coord), y(y_coord) {}

    bool operator==(const Point& other) const {
        if (this->x < 0) {
            return true;
        }
        return (this->x == other.x && this->y == other.y);
    }
};

std::string bool_to_string(bool b) {
    return b ? "true" : "false";
}

int main() {
